import{AttributeAction,SelectorType,isTraversal as isTraversalBase}from"css-what";export function isTraversal(t){return"_flexibleDescendant"===t.type||isTraversalBase(t)}export function sortRules(t){const e=t.map(getQuality);for(let r=1;r<t.length;r++){const a=e[r];if(!(a<0))for(let n=r;n>0&&a<e[n-1];n--){const r=t[n];t[n]=t[n-1],t[n-1]=r,e[n]=e[n-1],e[n-1]=a}}}function getAttributeQuality(t){switch(t.action){case AttributeAction.Exists:return 10;case AttributeAction.Equals:return"id"===t.name?9:8;case AttributeAction.Not:return 7;case AttributeAction.Start:case AttributeAction.End:return 6;case AttributeAction.Any:return 5;case AttributeAction.Hyphen:return 4;case AttributeAction.Element:return 3}}export function getQuality(t){switch(t.type){case SelectorType.Universal:return 50;case SelectorType.Tag:return 30;case SelectorType.Attribute:return Math.floor(getAttributeQuality(t)/(t.ignoreCase?2:1));case SelectorType.Pseudo:return t.data?"has"===t.name||"contains"===t.name||"icontains"===t.name?0:Array.isArray(t.data)?Math.max(0,Math.min(...t.data.map(t=>Math.min(...t.map(getQuality))))):2:3;default:return-1}}export function includesScopePseudo(t){return t.type===SelectorType.Pseudo&&("scope"===t.name||Array.isArray(t.data)&&t.data.some(t=>t.some(includesScopePseudo)))}